import { useEffect, useState } from "react"

// Define the possible screen sizes as a const array for better type inference
const SCREEN_SIZES = ["xs", "sm", "md", "lg", "xl", "2xl"] as const

// Create a union type from the array
export type ScreenSize = (typeof SCREEN_SIZES)[number]

// Type-safe size order mapping
const sizeOrder: Record<ScreenSize, number> = {
    xs: 0,
    sm: 1,
    md: 2,
    lg: 3,
    xl: 4,
    "2xl": 5,
} as const

class ComparableScreenSize {
    constructor(private value: ScreenSize) { }

    toString(): ScreenSize {
        return this.value
    }

    valueOf(): number {
        return sizeOrder[this.value]
    }

    // Add type predicate methods for better TypeScript support
    equals(other: ScreenSize): boolean {
        return this.value === other
    }

    lessThan(other: ScreenSize): boolean {
        return this.valueOf() < sizeOrder[other]
    }

    greaterThan(other: ScreenSize): boolean {
        return this.valueOf() > sizeOrder[other]
    }

    lessThanOrEqual(other: ScreenSize): boolean {
        return this.valueOf() <= sizeOrder[other]
    }

    greaterThanOrEqual(other: ScreenSize): boolean {
        return this.valueOf() >= sizeOrder[other]
    }
}

const useScreenSize = (): ComparableScreenSize => {
    const [screenSize, setScreenSize] = useState<ScreenSize>("xs")

    useEffect(() => {
        const handleResize = () => {
            const width = window.innerWidth

            if (width >= 1536) {
                setScreenSize("2xl")
            } else if (width >= 1280) {
                setScreenSize("xl")
            } else if (width >= 1024) {
                setScreenSize("lg")
            } else if (width >= 768) {
                setScreenSize("md")
            } else if (width >= 640) {
                setScreenSize("sm")
            } else {
                setScreenSize("xs")
            }
        }

        handleResize()
        window.addEventListener("resize", handleResize)
        return () => window.removeEventListener("resize", handleResize)
    }, [])

    return new ComparableScreenSize(screenSize)
}

export { useScreenSize }

"use client";

import { ArrowLeft, ArrowRight, ArrowUpRight } from "lucide-react";
import { useEffect, useState } from "react";

import { Button } from "@/components/ui/button";
import { Card, CardHeader, CardTitle, CardContent, CardFooter } from "@/components/ui/card";
import {
    Carousel,
    CarouselApi,
    CarouselContent,
    CarouselItem,
} from "@/components/ui/carousel";

interface GalleryItem {
    id: string;
    title: string;
    summary: string;
    url: string;
    image: string;
}

interface Gallery6Props {
    heading?: string;
    demoUrl?: string;
    items?: GalleryItem[];
}

const Gallery6 = ({
    heading = "Gallery",
    demoUrl = "#",
    items = [],
}: Gallery6Props) => {
    const [carouselApi, setCarouselApi] = useState<CarouselApi>();
    const [canScrollPrev, setCanScrollPrev] = useState(false);
    const [canScrollNext, setCanScrollNext] = useState(false);
    useEffect(() => {
        if (!carouselApi) {
            return;
        }
        const updateSelection = () => {
            setCanScrollPrev(carouselApi.canScrollPrev());
            setCanScrollNext(carouselApi.canScrollNext());
        };
        updateSelection();
        carouselApi.on("select", updateSelection);
        return () => {
            carouselApi.off("select", updateSelection);
        };
    }, [carouselApi]);
    return (
        <section className="py-24 sm:py-32">
            <div className="container mx-auto px-4 sm:px-6 lg:px-8">
                <div className="mb-8 flex flex-col justify-between md:mb-14 md:flex-row md:items-end lg:mb-16">
                    <div>
                        <h2 className="mb-3 text-3xl font-semibold md:mb-4 md:text-4xl lg:mb-6">
                            {heading}
                        </h2>
                        <a
                            href={demoUrl}
                            className="group flex items-center gap-1 text-sm font-medium md:text-base lg:text-lg hover:underline transition-all"
                        >
                            도입 문의하기
                            <ArrowUpRight className="size-4 transition-transform group-hover:translate-x-1" />
                        </a>
                    </div>
                    <div className="mt-8 flex shrink-0 items-center justify-start gap-2">
                        <Button
                            size="icon"
                            variant="outline"
                            onClick={() => {
                                carouselApi?.scrollPrev();
                            }}
                            disabled={!canScrollPrev}
                            className="disabled:pointer-events-auto"
                        >
                            <ArrowLeft className="size-5" />
                        </Button>
                        <Button
                            size="icon"
                            variant="outline"
                            onClick={() => {
                                carouselApi?.scrollNext();
                            }}
                            disabled={!canScrollNext}
                            className="disabled:pointer-events-auto"
                        >
                            <ArrowRight className="size-5" />
                        </Button>
                    </div>
                </div>
            </div>
            <div className="w-full">
                <Carousel
                    setApi={setCarouselApi}
                    opts={{
                        breakpoints: {
                            "(max-width: 768px)": {
                                dragFree: true,
                            },
                        },
                    }}
                    className="relative max-w-7xl mx-auto"
                >
                    <CarouselContent className="px-4">
                        {items.map((item) => (
                            <CarouselItem key={item.id} className="pl-4 md:max-w-[452px]">
                                <Card className="h-full group flex flex-col justify-between overflow-hidden cursor-pointer hover:shadow-lg transition-shadow">
                                    <a
                                        href={item.url}
                                        className="flex flex-col h-full"
                                    >
                                        <div className="flex aspect-[3/2] overflow-clip">
                                            <div className="relative h-full w-full origin-bottom transition duration-500 group-hover:scale-105">
                                                <img
                                                    src={item.image}
                                                    alt={item.title}
                                                    className="h-full w-full object-cover object-center"
                                                />
                                            </div>
                                        </div>
                                        <CardHeader className="pt-6">
                                            <CardTitle className="line-clamp-2 break-words text-xl font-bold md:text-2xl">
                                                {item.title}
                                            </CardTitle>
                                        </CardHeader>
                                        <CardContent className="flex-grow">
                                            <p className="line-clamp-3 text-sm text-foreground/80 md:text-base">
                                                {item.summary}
                                            </p>
                                        </CardContent>
                                        <CardFooter>
                                            <div className="flex items-center text-sm font-medium text-primary">
                                                자세히 보기{" "}
                                                <ArrowRight className="ml-2 size-4 transition-transform group-hover:translate-x-1" />
                                            </div>
                                        </CardFooter>
                                    </a>
                                </Card>
                            </CarouselItem>
                        ))}
                    </CarouselContent>
                </Carousel>
            </div>
        </section>
    );
};

export { Gallery6 };

import { InfiniteSlider } from "@/components/ui/infinite-slider";
import { cn } from "@/lib/utils";

type Logo = {
  src: string;
  alt: string;
  width?: number;
  height?: number;
};

type LogoCloudProps = React.ComponentProps<"div"> & {
  logos: Logo[];
};

export function LogoCloud({ className, logos, ...props }: LogoCloudProps) {
  return (
    <div
      {...props}
      className={cn(
        "overflow-hidden py-4 [mask-image:linear-gradient(to_right,transparent,black,transparent)]",
        className
      )}
    >
      <InfiniteSlider gap={42} reverse duration={80} durationOnHover={25}>
        {logos.map((logo) => (
          <img
            alt={logo.alt}
            className="pointer-events-none h-4 select-none md:h-5 dark:brightness-0 dark:invert"
            height={logo.height || "auto"}
            key={`logo-${logo.alt}`}
            loading="lazy"
            src={logo.src}
            width={logo.width || "auto"}
          />
        ))}
      </InfiniteSlider>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { AnimatePresence, motion, TargetAndTransition, Transition, VariantLabels } from "motion/react";

type MotionAnimation = TargetAndTransition | VariantLabels | boolean;

interface TextRotateProps {
    texts: string[];
    mainClassName?: string;
    splitLevelClassName?: string;
    staggerFrom?: "first" | "last" | "center" | number;
    initial?: TargetAndTransition | VariantLabels;
    animate?: TargetAndTransition | VariantLabels;
    exit?: TargetAndTransition | VariantLabels;
    staggerDuration?: number;
    transition?: Transition;
    rotationInterval?: number;
}

export function TextRotate({
    texts,
    mainClassName = "",
    splitLevelClassName = "",
    staggerFrom = "last",
    initial = { y: "100%" },
    animate = { y: 0 },
    exit = { y: "-120%" },
    staggerDuration = 0.025,
    transition = { type: "spring", damping: 30, stiffness: 400 },
    rotationInterval = 2000,
}: TextRotateProps) {
    const [index, setIndex] = useState(0);

    useEffect(() => {
        const id = setInterval(() => {
            setIndex((prev) => (prev + 1) % texts.length);
        }, rotationInterval);
        return () => clearInterval(id);
    }, [texts.length, rotationInterval]);

    return (
        <div className={`relative flex items-center ${mainClassName}`}>
            <AnimatePresence mode="wait">
                <motion.div
                    key={index}
                    className={`${splitLevelClassName} flex`}
                    initial={initial}
                    animate={animate}
                    exit={exit}
                    transition={transition}
                >
                    {texts[index].split("").map((char, i) => (
                        <motion.span
                            key={i}
                            className="inline-block"
                            transition={{
                                ...transition,
                                delay:
                                    staggerFrom === "last"
                                        ? (texts[index].length - i) * staggerDuration
                                        : i * staggerDuration,
                            }}
                        >
                            {char === " " ? "\u00A0" : char}
                        </motion.span>
                    ))}
                </motion.div>
            </AnimatePresence>
        </div>
    );
}
